INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-8b44517b-moex-00327', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「學習走路的孩子沒有不摔跤的，並且在千萬孩子之中，可能有一個摔成腦震盪。有一位母 親因此堅決不讓她的孩子走路，那孩子果然從來沒有摔過跤，身上也沒有疤痕，但最終變成 了癱子，一生要坐輪椅。人生有些痛苦是要受的，有些代價是要付的，有些過失是要犯的。」 根據上文，下列何者與本文旨意相去最遠？', '["父母過度的保護，會使孩子無法成長", "人不怕犯錯，只要知錯能改便能進步", "人本來就要不斷學習，不能因噎廢食", "生命是有限的，應多元嘗試各種事物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00328', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「『在矽谷，失敗不是一個選項，而是一個必需品。』這是美國雜誌對矽谷『包容失敗』文 化的經典評論。在這裡，人們更注重你是不是有創新的想法，有敢拚敢闖的精神，而不怕你 在努力中失敗。甚至，大家會覺得失敗是一件值得慶祝的驕傲事。」 根據上文，矽谷人認為失敗值得慶祝的原因是：', '["矽谷的人大多有失敗經驗", "能透過失敗學會彼此包容", "比起失敗更讚許冒險嘗試", "失敗有助於弭平人我偏見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00329', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「臺灣火刺木原生於臺灣東部，主要分布於海岸山脈的低海拔溪流河床區域，是能耐乾旱、 貧瘠的常綠灌木，未經修剪的植株約可長至3公尺高。園藝界常稱為狀元紅，這其實是對薔 薇科火刺木屬植物的通稱，本屬植物果實均紅豔如火，且莖上長著棘刺，而有此屬名。如要 辨認出臺灣火刺木，可觀其葉片，先端微凹且無細鋸齒緣，邊緣光滑無缺刻，就是明顯特徵。 果實滋味微酸，不少花東地區長輩憶起童年時代，會將臺灣火刺木的紅果稱為小蘋果。」 根據上文，下列敘述何者最適當？', '["狀元紅是一種修長、全身通紅且有棘刺的灌木", "小蘋果的得名是來自果皮顏色鮮紅與微酸滋味", "生於潮濕河流中的火刺木由親水性變成耐乾旱", "種植臺灣火刺木要提防被尖刺與鋸齒樹葉割傷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00330', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「哈佛大學教授列維研究過去五十年美國工作的變化，發現消失最快的是那些  ①  的工', '["，曾經使人們能維持不錯的生活， 像是收費員、打字員等工作，如今不是被外包，就是被新科技取代。」 根據上文，", "和", "最適合填入的是：", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00331', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列題辭，適用於祝賀新居落成的是：', '["宜其家室", "乾坤定矣", "氣象維新", "昌宜五世 美輪美奐"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00332', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列「」中的詞語，使用適當的是：', '["趙先生熱心服務「桑梓」，令人敬重", "不想為「五斗米」折腰，最好自己創業", "今年五月，有不少民意代表都「掛冠」下臺", "我覺得自己「馬齒」徒長，五十歲了還一事無成 他已經「請纓」多次，沒想到老闆還是不肯原諒他"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00333', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '下列成語能表達「經過長時間努力，終究會成功」的是：', '["九轉功成", "水滴石穿", "出人頭地", "老鶴乘軒 鐵杵磨針"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00334', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「池塘邊的榕樹上，知了在聲聲叫著夏天。操場邊的鞦韆上，只有蝴蝶停在上面。黑板上老 師的粉筆，還在拚命嘰嘰喳喳寫個不停。等待著下課，等待著放學，等待遊戲的童年。福利 社裡面什麼都有，就是口袋裡沒有半毛錢，諸葛四郎和魔鬼黨，到底誰搶到那支寶劍，隔壁 班的那個女孩，怎麼還沒經過我的窗前，嘴裡的零食，手裡的漫畫，心裡初戀的童年。陽光 下蜻蜓飛過來，一片片綠油油的稻田，水彩蠟筆和萬花筒，畫不出天邊那一條彩虹，什麼時 候才能像高年級的同學有張成熟與長大的臉。盼望著假期，盼望著明天，盼望長大的童年。 一天又一天，一年又一年，盼望長大的童年。」 根據上文，下列那些文句不僅描寫眼前的事物，也呈現內心的活動？', '["池塘邊的榕樹上，知了在聲聲叫著夏天", "福利社裡面什麼都有，就是口袋裡沒有半毛錢", "隔壁班的那個女孩，怎麼還沒經過我的窗前", "陽光下蜻蜓飛過來，一片片綠油油的稻田 水彩蠟筆和萬花筒，畫不出天邊那一條彩虹"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00335', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「不要寄望法律有那麼強大的理性功能，意思也就是不要寄望法律對公平正義都會有一個清 楚的輪廓。不過，這種對法律謙虛的期待或許現實上是不切實際的，因為法院案源的急速膨 脹突顯兩件事情，一個是人對彼此包容性的減低，另外一個是人對法律理性的迷信。但無論 如何，如果不是人們相互之間多一些包容的意願，即使法律設計出什麼制度，問題終究難以 根本解決。」 根據上文，下列敘述符合文意的是：', '["法律制度最重要的特質是強大的理性功能", "人民對法律謙虛的期待造成法院案源膨脹", "法律制度具備一定的公平正義但有其限度", "人們相互包容是法律問題的根本解決之道 我們應該修改法律直到它能主持人間正義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00336', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「想化危機為轉機，恢復企業停滯的業務，必須在一開始採取正確的行動。縱使在最破碎的 公司裡，十件事中仍有八件事是由優秀人才所完成。因此，增加獲利的有效方法之一，就是 表揚出色人員。這樣，對身處公司復原期的層峰主管而言，可以建立領導信心；對員工而言， 則可以感受到上級的信任，並且知道該朝什麼方向努力。」 根據上文，下列敘述符合文意的是：', '["受復原期影響，優秀人才發揮有限", "主管自我表彰，可為員工樹立標竿", "善用獎勵策略，能助員工確立目標", "鼓舞優秀員工，可以改善企業文化 福利措施越多，越能給予員工動力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
